        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('d74')._controlBehavior;
var l = g._getColumnOrder('stt_rec_nm');
var e = (v ? 'Thông tin khách hàng của phiếu nhập phải giống với phiếu nhập mua hàng.' : 'Voucher should have same customer information as purchase receipt.');

if (l >= 0 && f._checked) {
  var t = f.getItemValue('ma_kh');
  for (var i = 1; i <= g._rowCount; i++) {
    if (g._getItemValue(i, l)) {
      var u = g._getItem(i, 1)._customerIdentity;
      if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
      if (t != u) {
        $func.hideWait(id);
        $message.show(e, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
        f._checked = false;
        break;
      }
    }
  }
}
/* </flatten> */
