script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');&InitFormVisibleField;}
function active$Voucher$(f) {&ScriptActiveVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &LoadFormVisibleField;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d74')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d74')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt:t_tien');
    v.addGridFields(g, 'gia_nt,tien_nt:gia,tien');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged(['d74', 'so_ct_goc'&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d74', 'so_ct_goc'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('ong_ba', result[0].Value, null, true);
      f.live(f.getItem('ong_ba'));
      f._refAccount = result[1].Value;
      f._reasonCode = result[2].Value;
      set$Voucher$RefAccount(f);
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      set$Voucher$RefAccount(f);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$RefAccount(f) {
  var g = f.getItem("d74")._controlBehavior, t = (f.getItemValue('loai_ct') == '3');
  var o0 = g._activeCell, l0 = g._getColumnOrder('tk_du'), l1 = g._getColumnOrder('ma_nx');
  if (t) {
    for (var i = 0; i < g._rowCount; i++) {
      o0 = g._getItem(i + 1, l0), o1 = g._getItem(i + 1, l1);
      if (!o0.row) {
        if (o0.value == '') {
          o0.value = f._refAccount;
          o1.value = f._reasonCode;
        }
      } else {
        if (g._getItemValue(i + 1, l0) == '') {
          g._setItemValue(i + 1, l0, f._refAccount);
          g._setItemValue(i + 1, l1, f._reasonCode);
        }
      }
    }
  }
}
/* </flatten> */
